sys_script_include.script:
var api_tasker_template = Class.create();
api_tasker_template.prototype = {
    initialize: function() {
		// TOD< when moving to next release add this
		//this.api_dtech = new api_dtech_common();
		this.table_template_task = "x_153465_discovert_route_tasks";
		this.templateCopyMoveMethods = new template_Copy_Move_Methods();
    },

	cloneTemplate: function (template_id, new_template_name, new_template_owner){
		// this is JSON with new task and success flag
		var cloneResponse;
		cloneResponse =  this.templateCopyMoveMethods.cloneTemplate(template_id, new_template_name, new_template_owner);
		return cloneResponse;		
	}, 

	copyTemplateTask: function(templateTaskId, newParentId){
		var templateTaskCopied = false;
		templateTaskCopied =  this.templateCopyMoveMethods.copyTemplateTask(templateTaskId, newParentId);
		return templateTaskCopied;
	},

	copyTemplateTaskAndDescendants: function(templateTaskId, newParentId){
		var templateTaskCopied = false;
		templateTaskCopied =  this.templateCopyMoveMethods.copyTemplateTaskAndDescendants(templateTaskId, newParentId);
		return templateTaskCopied;
	},

	isTemplateNameUnique: function(template_name, template_level, template_ou, template_owner){
		var nameExists = false;
		var isTemplateNameUnique = false;
		nameExists = this.templateCopyMoveMethods.checkIfNameExists(template_name, template_level, template_ou, template_owner);
		isTemplateNameUnique = !nameExists;
		return isTemplateNameUnique;
	},

	moveTemplateTask: function(templateTaskId, newParentId){
		var templateTaskMoved = false;
		templateTaskMoved =  this.templateCopyMoveMethods.moveTemplateTask(templateTaskId, newParentId);
		return templateTaskMoved;
	},

	validateMetaData: function(methodCalled, metaData){
		var validMetaData = {};
		var isMetadataValid = false;
		if(typeof(metaData) == 'object'){
			if(metaData.objId && metaData.newParentId){
				validMetaData = metaData;
				isMetadataValid = true;
				validMetaData.success = true;
			}
		}
		validMetaData.validCallData = isMetadataValid;
		if(!isMetadataValid){
			gs.addErrorMessage("Tasker - " + methodCalled + " - invalid data: " + metaData);
			validMetaData.success = false;
			validMetaData.error = "invalid information provided for " + methodCalled;
		}
		return validMetaData;
	},

	validateNameCheckMetaData: function(methodCalled, metaData){
		var validMetaData = {};
		var isMetadataValid = false;
		if(typeof(metaData) == 'object'){
			if(metaData.new_template_name && metaData.new_template_name != '' &&
				metaData.template_level && metaData.template_level != '' &&
				metaData.template_ou && metaData.template_ou != '' &&
				metaData.template_owner && metaData.template_owner != ''){
				validMetaData = metaData;
				isMetadataValid = true;
			}
		}
		validMetaData.validCallData = isMetadataValid;
		if(!isMetadataValid){
			gs.addErrorMessage("Tasker - " + methodCalled + " - invalid data: " + metaData);
			validMetaData.success = false;
			validMetaData.error = "invalid information provided for " + methodCalled;
		}
		return validMetaData;	
	},

	validateCloneMetaData: function(methodCalled, metaData){
		var validMetaData = {};
		var isMetadataValid = false;
		if(typeof(metaData) == 'object'){
			if(metaData.template_id && metaData.template_id != '' &&
				metaData.new_template_owner && metaData.new_template_owner != '' &&
				metaData.new_template_name && metaData.new_template_name != ''){
				validMetaData = metaData;
				isMetadataValid = true;
			}
		}
		validMetaData.validCallData = isMetadataValid;
		if(!isMetadataValid){
			gs.addErrorMessage("Tasker - " + methodCalled + " - invalid data: " + metaData);
			validMetaData.success = false;
			validMetaData.error = "invalid information provided for " + methodCalled;
		}
		return validMetaData;	
	},

    type: 'api_tasker_template'
};
